import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - empty and processing fee", () => {
    it.todo("should return 5 G premium for an empty items list (processing fee only)");
  });

  describe("quote - single item base premiums", () => {
    it.todo("should return 105 G for a single plain sword (100 base + 5 fee)");
    it.todo("should return 65 G for a single plain amulet (60 base + 5 fee)");
    it.todo("should return 85 G for a single plain staff (80 base + 5 fee)");
    it.todo("should return 45 G for a single plain potion (40 base + 5 fee)");
    it.todo("should return 30 G for a single rune component (25 base + 5 fee)");
  });

  describe("quote - component blocks of 3 alike", () => {
    it.todo("should return 55 G for 2 runes (50 base + 5 fee, no block)");
    it.todo("should return 65 G for 3 runes (60 base block discount + 5 fee)");
    it.todo("should return 105 G for 4 runes (100 base, no block since not exactly 3 + 5 fee)");
    it.todo("should return 180 G for 7 runes (175 base + 5 fee)");
    it.todo("should return 80 G for 2 runes + 1 moonstone (75 base, no block due to different types + 5 fee)");
    it.todo("should return 125 G for 3 runes + 3 moonstones (120 base, two separate blocks + 5 fee)");
  });

  describe("quote - item-specific modifiers", () => {
    it.todo("should add 50% curse surcharge to a cursed sword's base premium");
    it.todo("should add 30% high-enchantment surcharge for sword with enchantment exactly 5");
    it.todo("should not add high-enchantment surcharge for sword with enchantment 4");
    it.todo("should add both curse and high-enchantment surcharges to a cursed highly enchanted sword");
  });

  describe("quote - policy-wide modifiers", () => {
    it.todo("should apply 20% loyalty discount for customer with exactly 2 years with MHPCO");
    it.todo("should not apply loyalty discount for customer with less than 2 years");
    it.todo("should add 10% first insurance surcharge per item base premium");
    it.todo("should apply 15% follow-up contract discount on second contract");
  });

  describe("quote - modifier scope on multi-item policies", () => {
    it.todo("should apply curse surcharge only to the cursed item, not to the policy total (cursed sword + plain amulet → 210 G before fee)");
    it.todo("should still apply first-insurance surcharge per item even on follow-up contract");
  });

  describe("quote - integration examples", () => {
    it.todo("should compute 165 G for newcomer (0 years, no prior) with cursed steel sword enchantment 3");
    it.todo("should compute 160 G for 3-year customer's second contract with cursed steel sword enchantment 7");
  });

  describe("quote - rounding", () => {
    it.todo("should round premium up in MHPCO favor (e.g. 197.5 G → 198 G)");
    it.todo("should keep intermediate amounts as fractions and round only the final premium");
  });

  describe("claim - basic single-item reimbursement", () => {
    it.todo("should pay 400 G for standard steel sword enchantment 3 with 500 G damage (full minus 100 deductible)");
    it.todo("should pay 100 G for a rune with 200 G damage (full minus 100 deductible)");
    it.todo("should report remaining cap after a basic claim (sword cap 2000, claim 500 → remaining 1600)");
  });

  describe("claim - high enchantment clause", () => {
    it.todo("should reimburse at 50% then deductible for steel sword enchantment 9 with 1000 G damage → payout 400 G");
    it.todo("should apply high-enchantment 50% rule at exactly enchantment 8");
  });

  describe("claim - dragon material clause", () => {
    it.todo("should fully reimburse dragon-material sword enchantment 5 with 800 G damage → payout 700 G");
    it.todo("should let 50% rule win for dragon sword enchantment 9 with 1000 G damage → payout 400 G");
  });

  describe("claim - multiple items / deductible per event", () => {
    it.todo("should apply deductible once per damaged item (sword 500 + amulet 300 → payout 600 G)");
    it.todo("should treat two same-type damages as separate events with own deductibles");
    it.todo("should reject claim when damages contain more entries of a type than insured");
  });

  describe("claim - cap exhaustion", () => {
    it.todo("should cap a single claim at 2x insurance value (sword cap 2000, damage 1500 → payout 1400, remaining 600)");
    it.todo("should reduce later claims to remaining cap (second 1500 G claim → payout 600, remaining 0)");
    it.todo("should base cap on unmodified insurance value, not on premium modifiers (cursed sword cap = 2000)");
    it.todo("should compute insurance sum from item insurance values, ignoring component block discount on cap (sword + 3 runes → cap 3500)");
  });

  describe("claim - error cases", () => {
    it.todo("should reject claim where damaged item type is not part of the policy");
    it.todo("should reject claim with negative damage amount");
  });

  describe("claim - rounding", () => {
    it.todo("should round payout down in MHPCO favor (e.g. 350.5 G → 350 G)");
  });

  describe("CLI - JSON in/out", () => {
    it.todo("should read scenario JSON from stdin and write results JSON to stdout");
    it.todo("should produce a quote result with {premium} for a quote step");
    it.todo("should produce a claim result with {payout, remainingCap} for a claim step");
    it.todo("should process steps sequentially and reference policies by step index");
    it.todo("should track customer history (yearsWithMHPCO, follow-up contract) across scenario steps");
    it.todo("should exit non-zero and write to stderr for an unknown item type in a quote");
    it.todo("should exit non-zero and write to stderr for a claim referencing an item not in the policy");
    it.todo("should exit non-zero and write to stderr for a claim with negative damage amount");
    it.todo("should exit non-zero when claim has more damages of a type than insured");
  });
});

