export type Customer = {
  yearsWithMHPCO: number;
  priorContracts: number;
};

export type Item = Record<string, unknown>;

export type Policy = {
  customer: Customer;
  items: Item[];
};

export type QuoteResult = {
  premium: number;
};

export type ClaimResult = {
  payout: number;
  remainingCap: number;
};

const PROCESSING_FEE = 5;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

const basePremiumForItem = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type as string] ?? 0;

export function quote(policy: Policy): QuoteResult {
  const basePremium = policy.items.reduce(
    (sum, item) => sum + basePremiumForItem(item),
    0,
  );
  return { premium: basePremium + PROCESSING_FEE };
}

export function claim(..._args: unknown[]): ClaimResult {
  return undefined as unknown as ClaimResult;
}

