  customer.priorContracts >= FOLLOW_UP_PRIOR_CONTRACTS_THRESHOLD
    ? -basePremium * FOLLOW_UP_DISCOUNT_RATE
    : 0;

const POLICY_ADJUSTMENTS: PolicyAdjustment[] = [
  loyaltyAdjustment,
