      expect(() =>
        claim(
          { items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
          { cause: "fire", damages: [{ itemType: "sword", amount: -200 }] },
        ),
      ).toThrow();
    });
  });

  describe("claim - rounding", () => {
    it("should round payout down in MHPCO favor (e.g. 350.5 G → 350 G)", () => {
